Функция ДействующийДоговорНаДату(КонтрагентСсылка, ДатаСреза) Экспорт

	Запрос = Новый Запрос;
	Запрос.Текст =
	"ВЫБРАТЬ ПЕРВЫЕ 1
	|	Договоры.Ссылка КАК Ссылка
	|ИЗ
	|	Справочник.Договоры КАК Договоры
	|ГДЕ
	|	Договоры.Владелец = &Контрагент
	|	И Договоры.ДатаНачала <= &ДатаСреза
	|	И (Договоры.ДатаОкончания >= &ДатаСреза
	|		ИЛИ Договоры.ДатаОкончания = ДАТАВРЕМЯ(1, 1, 1))
	|УПОРЯДОЧИТЬ ПО
	|	Договоры.ДатаНачала УБЫВ";

	Запрос.УстановитьПараметр("Контрагент", КонтрагентСсылка);
	Запрос.УстановитьПараметр("ДатаСреза", ДатаСреза);

	Выборка = Запрос.Выполнить().Выбрать();

	Если Выборка.Следующий() Тогда
		Возврат Выборка.Ссылка;
	КонецЕсли;

	Возврат Неопределено;

КонецФункции
